1	//! R2 — rule rendering: the whole rule block, byte-identical to the echo.
2	//!
3	//! Every layout decision is oracle-pinned (see workspace/BEHAVIOR.md "Rule
4	//! blocks" for probe provenance). Shape summary:
5	//!
6	//! ```text
7	//! rule (modulo E) Name[color=#abcdef, no_derivcheck, issapicrule,
8	//!                      role='r']:
9	//!    [ Prem( x ), !Persistent( y )[+, no_precomp] ]
10	//!   --[ Act( x ) ]->
11	//!    [ Concl( x ) ]
12	//!
13	//!   // loop breakers: [0,1]
14	//!   /* has exactly the trivial AC variant */
15	//! ```
16	//!
17	//! * body = `nest 3 (sep [prems, nest (-1) arrow, concls])` — one line when
18	//!   it fits, otherwise premises/conclusions at indent 3 and the arrow row at
19	//!   indent 2;
20	//! * each bracket group = `sep ["[", fsep facts, "]"]` (`[ ]` when empty);
21	//!   the empty-action arrow is the literal `-->`;
22	//! * a fact = `sep [name<>"(" <+> fsep args, ")"]` (`Name( )` when nullary)
23	//!   with the annotation suffix attached after the `)`;
24	//! * the trailing comment is either the trivial-variant one-liner or the
25	//!   `/* rule (modulo AC) … variants (modulo AC) … */` block with numbered
26	//!   substitution groups: number right-aligned to the widest index, each
27	//!   substitution `lhs $$ nest 6 ("= " <> rhs)` — the HughesPJ overlap pads
28	//!   a short lhs to column 6 and pushes `= rhs` to its own line otherwise.
29	
30	use crate::ast::{AcVariants, Fact, FactAnnotation, Rule, RuleAttr, Term};
31	use crate::doc::{
32	    above_op, above_plus, beside_op, beside_space, char, fsep, nest, punctuate,
33	    render_with, sep, text, vcat, Doc,
34	};
35	use crate::term::{self, RIBBON, WIDTH};
36	
37	/// One fact: `Name( arg, … )`, persistent prefixed with `!`, annotations
38	/// attached after the closing paren.
39	pub fn render_fact(f: &Fact) -> String {
40	    render_with(WIDTH, RIBBON, &fact_doc(f))
41	}
42	
43	/// One whole rule block: header, body, blank line, loop-breaker annotation,
44	/// and the AC-variants comment (`None` → the trivial-variant one-liner).
45	pub fn render(rule: &Rule, variants: Option<&AcVariants>) -> String {
46	    render_with(WIDTH, RIBBON, &block_doc(rule, variants))
47	}
48	
49	fn block_doc(rule: &Rule, variants: Option<&AcVariants>) -> Doc {
50	    let mut d = core_doc(rule);
51	    // `$+$` below the blank line: `$$` overlap would otherwise pull the
52	    // nested comment line up onto it.
53	    d = above_plus(d, text(""));
54	    if let Some(lb) = breaker_doc(&rule.loop_breakers) {
55	        d = above_plus(d, nest(2, &lb));
56	    }
57	    above_plus(d, nest(2, &comment_doc(variants)))
58	}
59	
60	/// Header + body (shared by the toplevel block and the AC rule re-rendered
61	/// inside the variants comment).
62	fn core_doc(rule: &Rule) -> Doc {
63	    above_op(header_doc(rule), nest(3, &body_doc(rule)))
64	}
65	
66	// ── header ──────────────────────────────────────────────────────────────────
67	
68	/// `rule (modulo E) Name:`, with the rendered attribute list in `[…]` before
69	/// the colon; attributes fill-wrap aligned after the `[`
70	/// (target:issue713, probe:p_rattr).
71	fn header_doc(rule: &Rule) -> Doc {
72	    let mut head = String::from("rule ");
73	    if let Some(m) = &rule.modulo {
74	        head.push_str(&format!("(modulo {m}) "));
75	    }
76	    head.push_str(&rule.name);
77	    let attrs = attr_items(&rule.attributes);
78	    if attrs.is_empty() {
79	        text(&format!("{head}:"))
80	    } else {
81	        beside_op(
82	            beside_op(
83	                text(&format!("{head}[")),
84	                fsep(punctuate(
85	                    &char(','),
86	                    attrs.iter().map(|a| text(a)).collect(),
87	                )),
88	            ),
89	            text("]:"),
90	        )
91	    }
92	}
93	
94	/// Canonical attribute list: color, no_derivcheck, issapicrule, role — the
95	/// last color/role declaration wins; `process=…` and external attributes are
96	/// dropped (probe:p_rattr, target:issue713).
97	fn attr_items(attrs: &[RuleAttr]) -> Vec<String> {
98	    let mut color = None;
99	    let mut no_derivcheck = false;
100	    let mut issapicrule = false;
101	    let mut role = None;
102	    for a in attrs {
103	        match a {
104	            RuleAttr::Color(c) => color = Some(c.clone()),
105	            RuleAttr::NoDerivCheck => no_derivcheck = true,
106	            RuleAttr::IsSapicRule => issapicrule = true,
107	            RuleAttr::Role(r) => role = Some(r.clone()),
108	            RuleAttr::Process(_) | RuleAttr::External(..) => {}
109	        }
110	    }
111	    let mut items = Vec::new();
112	    if let Some(c) = color {
113	        items.push(format!("color=#{c}"));
114	    }
115	    if no_derivcheck {
116	        items.push("no_derivcheck".into());
117	    }
118	    if issapicrule {
119	        items.push("issapicrule".into());
120	    }
121	    if let Some(r) = role {
122	        items.push(format!("role='{r}'"));
123	    }
124	    items
125	}
126	
127	// ── body ────────────────────────────────────────────────────────────────────
128	
129	/// `sep [prems, nest (-1) arrow, concls]` under the rule's nest 3: one line
130	/// `[ … ] --[ … ]-> [ … ]` when it fits, otherwise three rows with the arrow
131	/// out-dented one column (targets cav13/NSLPK3, probe:t_wide).
132	fn body_doc(rule: &Rule) -> Doc {
133	    sep(vec![
134	        fact_list_doc(&rule.premises),
135	        nest(-1, &arrow_doc(&rule.actions)),
136	        fact_list_doc(&rule.conclusions),
137	    ])
138	}
139	
140	/// `-->` when there are no actions, otherwise the `--[ … ]->` bracket group
141	/// (probe:p_arr1 rule AR pins the arrow to the SAME nested-sep construction
142	/// as the premise/conclusion lists: actions stay beside `--[` while `]->`
143	/// drops alone).
144	fn arrow_doc(actions: &[Fact]) -> Doc {
145	    if actions.is_empty() {
146	        text("-->")
147	    } else {
148	        bracket_group("--[", actions, "]->")
149	    }
150	}
151	
152	fn fact_list_doc(facts: &[Fact]) -> Doc {
153	    bracket_group("[", facts, "]")
154	}
155	
156	/// `sep [sep [open, fsep facts], close]` — a graded three-way layout
157	/// (probe:p_arr1; targets mesh ProvisionerWaitingUser vs DeviceWaitingUser,
158	/// NSLPK3 R_1/I_2, Tutorial Serv_1):
159	///   * everything on one line when `open facts close` fits (`[ f1, f2 ]`,
160	///     kept at exactly ribbon width — p_arr1 rule PR at 73);
161	///   * otherwise the closing bracket drops to the group's column; the
162	///     opening bracket keeps ALL the facts beside it iff they fit on that
163	///     line as a unit (mesh DeviceWaitingUser at exactly 73);
164	///   * otherwise the opening bracket is alone too and the facts fill-wrap
165	///     at the group's column between the brackets (NSLPK3 R_1: three facts
166	///     share a fill line; Serv_1: `--[` alone although the first action
167	///     would fit beside it).
168	fn bracket_group(open: &str, facts: &[Fact], close: &str) -> Doc {
169	    if facts.is_empty() {
170	        return sep(vec![text(open), text(close)]);
171	    }
172	    sep(vec![
173	        sep(vec![
174	            text(open),
175	            fsep(punctuate(&char(','), facts.iter().map(fact_doc).collect())),
176	        ]),
177	        text(close),
178	    ])
179	}
180	
181	// ── facts ───────────────────────────────────────────────────────────────────
182	
183	/// `Name( a, b )` — args fill-wrap aligned after `Name( `, the closing paren
184	/// drops to the fact's own column when the args are multi-line
185	/// (probe:t_wide); `Name( )` when nullary (target:mesh); `!` prefix for
186	/// persistent facts; annotation suffix attached directly after the paren.
187	/// Formula action atoms reuse this construction unchanged (probe:q_l3).
188	pub(crate) fn fact_doc(f: &Fact) -> Doc {
189	    let head = format!("{}{}(", if f.persistent { "!" } else { "" }, f.name);
190	    let core = if f.args.is_empty() {
191	        sep(vec![text(&head), char(')')])
192	    } else {
193	        sep(vec![
194	            beside_space(
195	                text(&head),
196	                fsep(punctuate(
197	                    &char(','),
198	                    f.args.iter().map(term::doc).collect(),
199	                )),
200	            ),
201	            char(')'),
202	        ])
203	    };
204	    match annotation_suffix(&f.annotations) {
205	        Some(s) => beside_op(core, text(&s)),
206	        None => core,
207	    }
208	}
209	
210	/// `[+, -, no_precomp]` in canonical order regardless of source order
211	/// (probe:p_fann `[no_precomp,+]` → `[+, no_precomp]`; target:seqdfsneeded
212	/// `[no_precomp,-]` → `[-, no_precomp]`).
213	fn annotation_suffix(annotations: &[FactAnnotation]) -> Option<String> {
214	    if annotations.is_empty() {
215	        return None;
216	    }
217	    let mut sorted: Vec<FactAnnotation> = annotations.to_vec();
218	    sorted.sort();
219	    sorted.dedup();
220	    let spellings: Vec<&str> = sorted
221	        .iter()
222	        .map(|a| match a {
223	            FactAnnotation::SolveFirst => "+",
224	            FactAnnotation::SolveLast => "-",
225	            FactAnnotation::NoSources => "no_precomp",
226	        })
227	        .collect();
228	    Some(format!("[{}]", spellings.join(", ")))
229	}
230	
231	// ── loop breakers ───────────────────────────────────────────────────────────
232	
233	/// `// loop breaker: [0]` / `// loop breakers: [0,1]` — plural iff several,
234	/// indices comma-separated without spaces (probes c_loop, p_lb2).
235	fn breaker_doc(indices: &[usize]) -> Option<Doc> {
236	    if indices.is_empty() {
237	        return None;
238	    }
239	    let list = indices
240	        .iter()
241	        .map(|i| i.to_string())
242	        .collect::<Vec<_>>()
243	        .join(",");
244	    let noun = if indices.len() == 1 {
245	        "loop breaker"
246	    } else {
247	        "loop breakers"
248	    };
249	    Some(text(&format!("// {noun}: [{list}]")))
250	}
251	
252	// ── the AC-variants comment ─────────────────────────────────────────────────
253	
254	/// `None` → the trivial one-liner; otherwise the comment block re-rendering
255	/// the AC rule, its numbered substitution groups, and its loop-breaker line
256	/// (probes p_var1, p_lbvar; targets cav13/Joux/CH07/mesh).
257	fn comment_doc(variants: Option<&AcVariants>) -> Doc {
258	    let Some(v) = variants else {
259	        return text("/* has exactly the trivial AC variant */");
260	    };
261	    let mut d = above_op(text("/*"), core_doc(&v.ac_rule));
262	    if !v.substitutions.is_empty() {
263	        d = above_op(d, nest(2, &substitutions_doc(&v.substitutions)));
264	    }
265	    if let Some(lb) = breaker_doc(&v.ac_rule.loop_breakers) {
266	        d = above_op(d, nest(2, &lb));
267	    }
268	    above_op(d, text("*/"))
269	}
270	
271	/// `variants (modulo AC)` and the numbered groups, separated by lines of
272	/// bare indent (four spaces at the observed nesting — probe:p_var1 byte
273	/// check); numbers right-aligned to the widest index (`  1.` … `160.` —
274	/// targets cav13 (1 digit), CH07 (2), Joux (3)).
275	fn substitutions_doc(groups: &[Vec<(Term, Term)>]) -> Doc {
276	    let width = groups.len().to_string().len();
277	    let mut rows = vec![text("variants (modulo AC)")];
278	    for (i, group) in groups.iter().enumerate() {
279	        if i > 0 {
280	            rows.push(text(""));
281	        }
282	        let prefix = format!("{:>width$}. ", i + 1);
283	        rows.push(beside_op(
284	            text(&prefix),
285	            vcat(group.iter().map(|(l, r)| substitution_doc(l, r)).collect()),
286	        ));
287	    }
288	    vcat(rows)
289	}
290	
291	/// One substitution: `lhs $$ nest 6 ("= " <> rhs)` — the overlap pads a
292	/// short lhs to column 6 (`~lv2  = ~lv2.4`) and drops `= rhs` to its own
293	/// line at column 6 when the lhs is 6 columns or wider (probe:p_var1
294	/// `~longvariablenameone`); the rhs is a full R1 term with its own wrapping
295	/// (target:mesh multi-line substitution values).
296	fn substitution_doc(lhs: &Term, rhs: &Term) -> Doc {
297	    above_op(
298	        term::doc(lhs),
299	        nest(6, &beside_op(text("= "), term::doc(rhs))),
300	    )
301	}
302

1	//! A faithful Rust port of the Hughes/Peyton-Jones pretty-printing library
2	//! `Text.PrettyPrint.HughesPJ` (Haskell `pretty` 1.1.3.6, BSD-licensed).
3	//!
4	//! OUT OF THE GPL-ERASURE SURFACE: this layout algebra was clean-roomed by the
5	//! graphdot cluster from the sanctioned BSD source
6	//! (`graphdot/sanctioned/pretty-1.1.3.6/src/Text/PrettyPrint/Annotated/
7	//! HughesPJ.hs`) and is vendored here unchanged (BSD terms permit), plus one
8	//! addition: [`render_with`], a renderer entry point taking an explicit
9	//! integer ribbon width (the theory echo uses width 110 / ribbon 73).
10	//!
11	//! This module implements the `Doc` document model and the combinators, the
12	//! best/fits layout selection, and the `PageMode` renderer: `<>`/`<+>`,
13	//! `$$`/`$+$`, `hcat`/`hsep`/`vcat`, `sep`/`cat`, `fsep`/`fcat`, `nest`/
14	//! `hang`, and the `best`/`nicest`/`fits` fitting logic with `lineLength` and
15	//! `ribbonsPerLine`.
16	//!
17	//! Nothing in this file is tamarin-specific: it is the general layout algebra.
18	//! WHICH combinators the theory echo applies, with what literal strings and
19	//! nesting, is derived from black-box probes and lives in the sibling modules
20	//! (`term`, `signature`, …); this module is the exact engine they feed.
21	//!
22	//! The annotation machinery of the original is elided (this port renders to a
23	//! plain `String`), so `TextBeside` carries the text and its column width
24	//! directly instead of an `AnnotDetails`.
25	//!
26	//! **Evaluation strategy.** The Haskell original relies on lazy evaluation: the
27	//! combinators (`sep`/`fill`/`beside`/`aboveNest`) describe exponentially large
28	//! sets of layouts as union trees, but `best` only ever forces the branches it
29	//! inspects, and `fits` only forces the *first line* of a candidate. A naive
30	//! strict port materializes those whole trees (exponential in the number of
31	//! fill elements). This port mirrors the laziness explicitly: recursive
32	//! combinator continuations are built as [`Doc::Lazy`] thunks (forced on
33	//! demand, memoized), and the `nicest` union choice uses [`fits_ahead`], which
34	//! decides `fits (min w r - sl) (best' ...)` by walking the *unresolved*
35	//! branch's first line only. Both are pure evaluation-order mirrors of the
36	//! sanctioned semantics: the resolved layout is byte-identical.
37	
38	use std::cell::RefCell;
39	use std::rc::Rc;
40	
41	/// The abstract document type. A `Doc` denotes a *set* of layouts; a `Doc` with
42	/// no `Union`/`NoDoc` denotes a single layout. Mirrors the Haskell `Doc a`
43	/// constructors (annotations elided).
44	#[derive(Clone, Debug)]
45	pub enum Doc {
46	    /// An empty span (`empty`): no height, no width.
47	    Empty,
48	    /// `text "" $$ x` — a newline above `x`. Its argument is never `Empty`.
49	    NilAbove(Rc<Doc>),
50	    /// `text s <> x` — literal text (with its column width) beside `x`. The
51	    /// argument is never a `Nest`.
52	    TextBeside(Rc<str>, usize, Rc<Doc>),
53	    /// `nest k x` — indent `x` by `k` columns (`k` may be negative).
54	    Nest(isize, Rc<Doc>),
55	    /// `ul \`union\` ur` — a choice between two layouts that flatten equal.
56	    Union(Rc<Doc>, Rc<Doc>),
57	    /// The empty *set* of documents.
58	    NoDoc,
59	    /// `Beside l sep r` — `sep` = true means a space is inserted between.
60	    Beside(Rc<Doc>, bool, Rc<Doc>),
61	    /// `Above u never_overlap l` — `never_overlap` = true forbids overlap.
62	    Above(Rc<Doc>, bool, Rc<Doc>),
63	    /// A suspended sub-document (the strict mirror of a Haskell thunk):
64	    /// computed on first [`force`], then memoized. Only ever wraps an already
65	    /// *reduced* document (an RDoc — no `Beside`/`Above`).
66	    Lazy(Rc<LazyDoc>),
67	}
68	
69	/// The shared state of a [`Doc::Lazy`] thunk.
70	pub struct LazyDoc(RefCell<LazyState>);
71	
72	enum LazyState {
73	    Pending(Option<Box<dyn FnOnce() -> Doc>>),
74	    Forced(Doc),
75	}
76	
77	impl std::fmt::Debug for LazyDoc {
78	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
79	        match &*self.0.borrow() {
80	            LazyState::Pending(_) => write!(f, "Lazy(<pending>)"),
81	            LazyState::Forced(d) => write!(f, "Lazy({:?})", d),
82	        }
83	    }
84	}
85	
86	use Doc::*;
87	
88	fn rc(d: Doc) -> Rc<Doc> {
89	    Rc::new(d)
90	}
91	
92	/// Suspend a document computation (a thunk). The closure runs at most once.
93	fn lazy<F: FnOnce() -> Doc + 'static>(f: F) -> Doc {
94	    Lazy(Rc::new(LazyDoc(RefCell::new(LazyState::Pending(Some(
95	        Box::new(f),
96	    ))))))
97	}
98	
99	/// Force a document to its outermost non-`Lazy` constructor (shallow clone —
100	/// children stay shared via `Rc`). Thunks are computed once and memoized;
101	/// chains of thunks collapse to the final value.
102	fn force(d: &Doc) -> Doc {
103	    match d {
104	        Lazy(l) => {
105	            if let LazyState::Forced(v) = &*l.0.borrow() {
106	                return v.clone();
107	            }
108	            let f = match &mut *l.0.borrow_mut() {
109	                LazyState::Pending(f) => f.take().expect("re-entrant force"),
110	                LazyState::Forced(v) => return v.clone(),
111	            };
112	            let v = force(&f());
113	            *l.0.borrow_mut() = LazyState::Forced(v.clone());
114	            v
115	        }
116	        _ => d.clone(),
117	    }
118	}
119	
120	// ---------------------------------------------------------------------------
121	// Constructors (§ "Values and Predicates")
122	
123	/// A one-character document.
124	pub fn char(c: char) -> Doc {
125	    let mut buf = [0u8; 4];
126	    let s: &str = c.encode_utf8(&mut buf);
127	    TextBeside(Rc::from(s), 1, rc(Empty))
128	}
129	
130	/// A one-line literal string document; its width is its Unicode-scalar count.
131	pub fn text(s: &str) -> Doc {
132	    let len = s.chars().count();
133	    TextBeside(Rc::from(s), len, rc(Empty))
134	}
135	
136	/// Text with an explicit column width (`sizedText l s`); use width 0 for
137	/// non-printing text.
138	pub fn sized_text(len: usize, s: &str) -> Doc {
139	    TextBeside(Rc::from(s), len, rc(Empty))
140	}
141	
142	/// The empty document (identity for `<>`, `$$`, and list combinators).
143	pub fn empty() -> Doc {
144	    Empty
145	}
146	
147	/// Is this the empty document?
148	pub fn is_empty(d: &Doc) -> bool {
149	    matches!(force(d), Empty)
150	}
151	
152	
153	// ---------------------------------------------------------------------------
154	// Structural smart-constructors
155	
156	fn nil_above_(d: Rc<Doc>) -> Doc {
157	    NilAbove(d)
158	}
159	
160	fn text_beside_(s: Rc<str>, l: usize, d: Rc<Doc>) -> Doc {
161	    TextBeside(s, l, d)
162	}
163	
164	fn nest_(k: isize, d: Rc<Doc>) -> Doc {
165	    Nest(k, d)
166	}
167	
168	fn union_(a: Rc<Doc>, b: Rc<Doc>) -> Doc {
169	    Union(a, b)
170	}
171	
172	/// `reduceDoc`: push `Beside`/`Above` down into reduced form (RDoc).
173	pub fn reduce_doc(d: &Doc) -> Doc {
174	    match d {
175	        Beside(p, g, q) => beside(p, *g, &reduce_doc(q)),
176	        Above(p, g, q) => above(p, *g, &reduce_doc(q)),
177	        other => other.clone(),
178	    }
179	}
180	
181	// ---------------------------------------------------------------------------
182	// nest / mkNest / mkUnion
183	
184	/// `nest k p` — indent by `k` (may be negative).
185	pub fn nest(k: isize, p: &Doc) -> Doc {
186	    mk_nest(k, &reduce_doc(p))
187	}
188	
189	fn mk_nest(k: isize, d: &Doc) -> Doc {
190	    let df = force(d);
191	    match &df {
192	        Nest(k1, p) => mk_nest(k + k1, p),
193	        NoDoc => NoDoc,
194	        Empty => Empty,
195	        _ if k == 0 => df,
196	        _ => nest_(k, rc(df)),
197	    }
198	}
199	
200	fn mk_union(p: Doc, q: Doc) -> Doc {
201	    match force(&p) {
202	        Empty => Empty,
203	        pf => union_(rc(pf), rc(q)),
204	    }
205	}
206	
207	// ---------------------------------------------------------------------------
208	// Horizontal composition <> and <+>
209	
210	/// `p <> q` — beside.
211	pub fn beside_op(p: Doc, q: Doc) -> Doc {
212	    beside_(p, false, q)
213	}
214	
215	/// `p <+> q` — beside, separated by a space unless an argument is empty.
216	pub fn beside_space(p: Doc, q: Doc) -> Doc {
217	    beside_(p, true, q)
218	}
219	
220	fn beside_(p: Doc, g: bool, q: Doc) -> Doc {
221	    match (&p, &q) {
222	        (_, Empty) => p,
223	        (Empty, _) => q,
224	        _ => Beside(rc(p), g, rc(q)),
225	    }
226	}
227	
228	/// `beside p g q` (spec: `p <g> q`) over reduced docs. Union branches and the
229	/// text-tail continuation are suspended ([`lazy`]), mirroring the sanctioned
230	/// source's (non-`$!`) laziness.
231	fn beside(p: &Doc, g: bool, q: &Doc) -> Doc {
232	    let pf = force(p);
233	    match &pf {
234	        NoDoc => NoDoc,
235	        Union(p1, p2) => {
236	            let (p1, p2, qa, qb) = (p1.clone(), p2.clone(), q.clone(), q.clone());
237	            union_(
238	                rc(lazy(move || beside(&p1, g, &qa))),
239	                rc(lazy(move || beside(&p2, g, &qb))),
240	            )
241	        }
242	        Empty => q.clone(),
243	        Nest(k, p1) => nest_(*k, rc(beside(p1, g, q))),
244	        Beside(p1, g1, q1) => {
245	            if *g1 == g {
246	                beside(p1, *g1, &beside(q1, g, q))
247	            } else {
248	                beside(&reduce_doc(&pf), g, q)
249	            }
250	        }
251	        Above(..) => beside(&reduce_doc(&pf), g, q),
252	        NilAbove(p1) => nil_above_(rc(beside(p1, g, q))),
253	        TextBeside(s, l, p1) => {
254	            let (p1, q1) = (p1.clone(), q.clone());
255	            let rest = lazy(move || match force(&p1) {
256	                Empty => nil_beside(g, &q1),
257	                _ => beside(&p1, g, &q1),
258	            });
259	            text_beside_(s.clone(), *l, rc(rest))
260	        }
261	        Lazy(_) => unreachable!("beside: forced doc"),
262	    }
263	}
264	
265	/// `nilBeside g p` (spec: `text "" <g> p`).
266	fn nil_beside(g: bool, p: &Doc) -> Doc {
267	    let pf = force(p);
268	    match &pf {
269	        Empty => Empty,
270	        Nest(_, p1) => nil_beside(g, p1),
271	        _ => {
272	            if g {
273	                TextBeside(Rc::from(" "), 1, rc(pf))
274	            } else {
275	                pf
276	            }
277	        }
278	    }
279	}
