548	// ---------------------------------------------------------------------------
549	// fill (fcat / fsep)
550	
551	/// `fcat` — paragraph-fill version of `cat` (no inter-element space).
552	pub fn fcat(ds: Vec<Doc>) -> Doc {
553	    fill(false, ds)
554	}
555	
556	/// `fsep` — paragraph-fill version of `sep` (space between elements).
557	pub fn fsep(ds: Vec<Doc>) -> Doc {
558	    fill(true, ds)
559	}
560	
561	fn fill(g: bool, ds: Vec<Doc>) -> Doc {
562	    if ds.is_empty() {
563	        return Empty;
564	    }
565	    let mut it = ds.into_iter();
566	    let p = it.next().unwrap();
567	    let ys: Vec<Doc> = it.collect();
568	    fill1(g, &reduce_doc(&p), 0, &ys)
569	}
570	
571	fn fill1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
572	    let pf = force(p);
573	    match &pf {
574	        NoDoc => NoDoc,
575	        Union(p1, q) => {
576	            let (p1, q) = (p1.clone(), q.clone());
577	            let (ya, yb) = (ys.to_vec(), ys.to_vec());
578	            union_(
579	                rc(lazy(move || fill1(g, &p1, k, &ya))),
580	                rc(lazy(move || above_nest(&q, false, k, &fill(g, yb)))),
581	            )
582	        }
583	        Empty => mk_nest(k, &fill(g, ys.to_vec())),
584	        Nest(n, p1) => {
585	            let (n, p1, ys) = (*n, p1.clone(), ys.to_vec());
586	            nest_(n, rc(lazy(move || fill1(g, &p1, k - n, &ys))))
587	        }
588	        NilAbove(p1) => {
589	            let (p1, ys) = (p1.clone(), ys.to_vec());
590	            nil_above_(rc(lazy(move || {
591	                above_nest(&p1, false, k, &fill(g, ys))
592	            })))
593	        }
594	        TextBeside(s, l, p1) => {
595	            let li = *l as isize;
596	            let (p1, ys) = (p1.clone(), ys.to_vec());
597	            text_beside_(
598	                s.clone(),
599	                *l,
600	                rc(lazy(move || fill_nb(g, &p1, k - li, &ys))),
601	            )
602	        }
603	        Above(..) => panic!("fill1 Above"),
604	        Beside(..) => panic!("fill1 Beside"),
605	        Lazy(_) => unreachable!("fill1: forced doc"),
606	    }
607	}
608	
609	fn fill_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
610	    let pf = force(p);
611	    match &pf {
612	        Nest(_, p1) => fill_nb(g, p1, k, ys),
613	        Empty => {
614	            if ys.is_empty() {
615	                Empty
616	            } else if matches!(force(&ys[0]), Empty) {
617	                fill_nb(g, &Empty, k, &ys[1..])
618	            } else {
619	                fill_nbe(g, k, &ys[0], &ys[1..])
620	            }
621	        }
622	        _ => fill1(g, &pf, k, ys),
623	    }
624	}
625	
626	fn fill_nbe(g: bool, k: isize, y: &Doc, ys: &[Doc]) -> Doc {
627	    let k1 = if g { k - 1 } else { k };
628	    let y_one = elide_nest(&one_liner(&reduce_doc(y)));
629	    let left = nil_beside(g, &fill1(g, &y_one, k1, ys));
630	    let (y2, ys2) = (y.clone(), ys.to_vec());
631	    let right = lazy(move || {
632	        let mut rest = vec![y2];
633	        rest.extend(ys2);
634	        nil_above_nest(false, k, &fill(g, rest))
635	    });
636	    mk_union(left, right)
637	}
638	
639	fn elide_nest(d: &Doc) -> Doc {
640	    let df = force(d);
641	    match &df {
642	        Nest(_, d1) => d1.as_ref().clone(),
643	        _ => df,
644	    }
645	}
