448	// ── the layout-insensitive echo parser (test harness only) ──────────────────
449	//
450	// Parses a rendered rule block back into the crate AST. It skips ALL
451	// whitespace between tokens, so the re-rendered layout can only come from
452	// the renderer under test, never from the capture.
453	
454	struct P<'a> {
455	    s: &'a str,
456	    pos: usize,
457	}
458	
459	impl<'a> P<'a> {
460	    fn new(s: &'a str) -> Self {
461	        P { s, pos: 0 }
462	    }
463	
464	    fn rest(&self) -> &'a str {
465	        &self.s[self.pos..]
466	    }
467	
468	    fn ws(&mut self) {
469	        while let Some(c) = self.rest().chars().next() {
470	            if c.is_whitespace() {
471	                self.pos += c.len_utf8();
472	            } else {
473	                break;
474	            }
475	        }
476	    }
477	
478	    fn starts(&mut self, tok: &str) -> bool {
479	        self.ws();
480	        self.rest().starts_with(tok)
481	    }
482	
483	    fn eat(&mut self, tok: &str) -> bool {
484	        if self.starts(tok) {
485	            self.pos += tok.len();
486	            true
487	        } else {
488	            false
489	        }
490	    }
491	
492	    fn expect(&mut self, tok: &str) {
493	        assert!(
494	            self.eat(tok),
495	            "expected {tok:?} at …{:?}",
496	            &self.rest()[..self.rest().len().min(60)]
497	        );
498	    }
499	
500	    fn ident(&mut self) -> String {
501	        self.ws();
502	        let s: String = self
503	            .rest()
504	            .chars()
505	            .take_while(|c| c.is_ascii_alphanumeric() || *c == '_')
506	            .collect();
507	        assert!(!s.is_empty(), "expected ident at …{:?}", &self.rest()[..self.rest().len().min(40)]);
508	        self.pos += s.len();
509	        s
510	    }
511	
512	    fn digits(&mut self) -> String {
513	        let s: String = self
514	            .rest()
515	            .chars()
516	            .take_while(|c| c.is_ascii_digit())
517	            .collect();
518	        self.pos += s.len();
519	        s
520	    }
521	
522	    /// `name` or `name.idx` as a (name, idx) pair.
523	    fn name_idx(&mut self) -> (String, u64) {
524	        let name = self.ident();
525	        if self.rest().starts_with('.')
526	            && self.s[self.pos + 1..].chars().next().is_some_and(|c| c.is_ascii_digit())
527	        {
528	            self.pos += 1;
529	            let idx = self.digits().parse().unwrap();
530	            (name, idx)
531	        } else {
532	            (name, 0)
533	        }
534	    }
535	
536	    fn quoted(&mut self) -> String {
537	        self.expect("'");
538	        let end = self.rest().find('\'').expect("unterminated quote");
539	        let s = self.rest()[..end].to_string();
540	        self.pos += end + 1;
541	        s
542	    }
543	
544	    // ── terms ──
545	
546	    fn term(&mut self) -> Term {
547	        let mut t = self.atom();
548	        while self.starts("^") {
549	            self.pos += 1;
550	            let rhs = self.atom();
551	            t = Term::BinOp(BinOp::Exp, Box::new(t), Box::new(rhs));
552	        }
553	        t
554	    }
555	
556	    fn sorted_var(&mut self, sort: SortHint) -> Term {
557	        let (name, idx) = self.name_idx();
558	        Term::Var(VarSpec {
559	            name,
560	            idx,
561	            sort,
562	            typ: None,
563	        })
564	    }
565	
566	    fn atom(&mut self) -> Term {
567	        self.ws();
568	        let c = self.rest().chars().next().expect("term expected");
569	        match c {
570	            '\'' => Term::PubLit(self.quoted()),
571	            '~' => {
572	                self.pos += 1;
573	                if self.rest().starts_with('\'') {
574	                    Term::FreshLit(self.quoted())
575	                } else {
576	                    self.sorted_var(SortHint::Fresh)
577	                }
578	            }
579	            '$' => {
580	                self.pos += 1;
581	                self.sorted_var(SortHint::Pub)
582	            }
583	            '#' => {
584	                self.pos += 1;
585	                self.sorted_var(SortHint::Node)
586	            }
587	            '%' => {
588	                self.pos += 1;
589	                if self.rest().chars().next().is_some_and(|c| c.is_ascii_digit()) {
590	                    Term::NatLit(self.digits())
591	                } else {
592	                    self.sorted_var(SortHint::Nat)
593	                }
594	            }
595	            '<' => {
596	                self.pos += 1;
597	                let mut elems = vec![self.term()];
598	                while self.eat(",") {
599	                    elems.push(self.term());
600	                }
601	                self.expect(">");
602	                Term::Pair(elems)
603	            }
604	            '(' => {
605	                self.pos += 1;
606	                let first = self.term();
607	                let op = if self.starts("++") {
608	                    BinOp::Union
609	                } else if self.starts("%+") {
610	                    BinOp::NatPlus
611	                } else if self.starts("\u{2295}") {
612	                    BinOp::Xor
613	                } else if self.starts("*") {
614	                    BinOp::Mult
615	                } else {
616	                    panic!("AC operator expected at …{:?}", &self.rest()[..self.rest().len().min(40)]);
617	                };
618	                let glyph = match op {
619	                    BinOp::Union => "++",
620	                    BinOp::NatPlus => "%+",
621	                    BinOp::Xor => "\u{2295}",
622	                    BinOp::Mult => "*",
623	                    BinOp::Exp => unreachable!(),
624	                };
625	                let mut t = first;
626	                while self.eat(glyph) {
627	                    let rhs = self.term();
628	                    t = Term::BinOp(op, Box::new(t), Box::new(rhs));
629	                }
630	                self.expect(")");
631	                t
632	            }
633	            _ => {
634	                let (name, idx) = self.name_idx();
635	                if self.rest().starts_with('(') {
636	                    // Application (nullary symbols render bare, so `(` here
637	                    // always introduces at least one argument).
638	                    self.pos += 1;
639	                    let mut args = vec![self.term()];
640	                    while self.eat(",") {
641	                        args.push(self.term());
642	                    }
643	                    self.expect(")");
644	                    Term::App(name, args)
645	                } else {
646	                    Term::Var(VarSpec {
647	                        name,
648	                        idx,
649	                        sort: SortHint::Untagged,
650	                        typ: None,
651	                    })
652	                }
653	            }
654	        }
655	    }
656	
657	    // ── facts ──
658	
659	    fn fact(&mut self) -> Fact {
660	        self.ws();
661	        let persistent = self.eat("!");
662	        let name = self.ident();
663	        self.expect("(");
664	        self.ws();
665	        let mut args = Vec::new();
666	        if !self.rest().starts_with(')') {
667	            args.push(self.term());
668	            while self.eat(",") {
669	                args.push(self.term());
670	            }
671	        }
672	        self.expect(")");
673	        // Annotations attach with no whitespace after the paren.
674	        let mut annotations = Vec::new();
675	        if self.rest().starts_with('[') {
676	            self.pos += 1;
677	            loop {
678	                self.ws();
679	                if self.eat("+") {
680	                    annotations.push(FactAnnotation::SolveFirst);
681	                } else if self.eat("-") {
682	                    annotations.push(FactAnnotation::SolveLast);
683	                } else if self.eat("no_precomp") {
684	                    annotations.push(FactAnnotation::NoSources);
685	                } else {
686	                    panic!("annotation expected");
687	                }
688	                if !self.eat(",") {
689	                    break;
690	                }
691	            }
692	            self.expect("]");
693	        }
694	        Fact {
695	            persistent,
696	            name,
697	            args,
698	            annotations,
699	        }
700	    }
701	
702	    fn fact_seq(&mut self, close: &str) -> Vec<Fact> {
703	        self.ws();
704	        let mut facts = Vec::new();
705	        if !self.starts(close) {
706	            facts.push(self.fact());
707	            while self.eat(",") {
708	                facts.push(self.fact());
709	            }
710	        }
711	        self.expect(close);
712	        facts
713	    }
714	
715	    // ── rules ──
716	
717	    fn rule_core(&mut self) -> Rule {
718	        self.expect("rule");
719	        self.ws();
720	        let modulo = if self.eat("(modulo") {
721	            let m = self.ident();
722	            self.expect(")");
723	            Some(m)
724	        } else {
725	            None
726	        };
727	        self.ws();
728	        let name: String = self
729	            .rest()
730	            .chars()
731	            .take_while(|c| !matches!(c, '[' | ':') && !c.is_whitespace())
732	            .collect();
733	        self.pos += name.len();
734	        let mut attributes = Vec::new();
735	        if self.rest().starts_with('[') {
736	            self.pos += 1;
737	            loop {
738	                self.ws();
739	                if self.eat("color=#") {
740	                    let v: String = self
741	                        .rest()
742	                        .chars()
743	                        .take_while(|c| c.is_ascii_alphanumeric())
744	                        .collect();
745	                    self.pos += v.len();
746	                    attributes.push(RuleAttr::Color(v));
747	                } else if self.eat("no_derivcheck") {
748	                    attributes.push(RuleAttr::NoDerivCheck);
749	                } else if self.eat("issapicrule") {
750	                    attributes.push(RuleAttr::IsSapicRule);
751	                } else if self.eat("role='") {
752	                    let end = self.rest().find('\'').unwrap();
753	                    attributes.push(RuleAttr::Role(self.rest()[..end].into()));
754	                    self.pos += end + 1;
755	                } else {
756	                    panic!("attribute expected at …{:?}", &self.rest()[..self.rest().len().min(40)]);
757	                }
758	                if !self.eat(",") {
759	                    break;
760	                }
761	            }
762	            self.expect("]");
763	        }
764	        self.expect(":");
765	        self.expect("[");
766	        let premises = self.fact_seq("]");
767	        self.ws();
768	        let actions = if self.eat("-->") {
769	            Vec::new()
770	        } else {
771	            self.expect("--[");
772	            self.fact_seq("]->")
773	        };
774	        self.expect("[");
775	        let conclusions = self.fact_seq("]");
776	        Rule {
777	            name,
778	            modulo,
779	            attributes,
780	            premises,
781	            actions,
782	            conclusions,
783	            loop_breakers: vec![],
784	        }
785	    }
786	
787	    /// `// loop breaker: [0]` / `// loop breakers: [0,1]`.
788	    fn breaker_line(&mut self) -> Vec<usize> {
789	        self.expect("//");
790	        self.ws();
791	        assert!(self.eat("loop breakers:") || self.eat("loop breaker:"));
792	        self.expect("[");
793	        let mut ids = vec![self.digits().parse().unwrap()];
794	        while self.eat(",") {
795	            self.ws();
796	            ids.push(self.digits().parse().unwrap());
797	        }
798	        self.expect("]");
799	        ids
800	    }
801	}
