803	/// Parse one extracted rule block into (Rule, Option<AcVariants>).
804	fn parse_block(block: &str) -> (Rule, Option<AcVariants>) {
805	    let mut p = P::new(block);
806	    let mut r = p.rule_core();
807	    if p.starts("//") {
808	        r.loop_breakers = p.breaker_line();
809	    }
810	    p.expect("/*");
811	    if p.eat("has exactly the trivial AC variant") {
812	        p.expect("*/");
813	        return (r, None);
814	    }
815	    let mut ac = p.rule_core();
816	    let mut substitutions: Vec<Vec<(Term, Term)>> = Vec::new();
817	    if p.eat("variants (modulo AC)") {
818	        loop {
819	            if p.starts("*/") || p.starts("//") {
820	                break;
821	            }
822	            // A group index (`12.`) or the next substitution's lhs.
823	            p.ws();
824	            if p.rest().chars().next().is_some_and(|c| c.is_ascii_digit()) {
825	                let n: usize = p.digits().parse().unwrap();
826	                p.expect(".");
827	                assert_eq!(n, substitutions.len() + 1, "group numbering");
828	                substitutions.push(Vec::new());
829	                continue;
830	            }
831	            let lhs = p.term();
832	            p.expect("=");
833	            let rhs = p.term();
834	            substitutions
835	                .last_mut()
836	                .expect("substitution before group index")
837	                .push((lhs, rhs));
838	        }
839	    }
840	    if p.starts("//") {
841	        ac.loop_breakers = p.breaker_line();
842	    }
843	    p.expect("*/");
844	    (
845	        r,
846	        Some(AcVariants {
847	            ac_rule: ac,
848	            substitutions,
849	        }),
850	    )
851	}
