426	// ── the layout-insensitive echo parser (test harness only) ──────────────────
427	//
428	// Parses rendered restriction/lemma blocks back into the crate AST. It skips
429	// ALL whitespace between tokens, so the re-rendered layout can only come
430	// from the renderer under test, never from the capture. Guarded content and
431	// proof scripts are extracted line-wise as VERBATIM opaque inputs (they are
432	// inputs to the renderer, not its output).
433	
434	struct P<'a> {
435	    s: &'a str,
436	    pos: usize,
437	}
438	
439	impl<'a> P<'a> {
440	    fn new(s: &'a str) -> Self {
441	        P { s, pos: 0 }
442	    }
443	
444	    fn rest(&self) -> &'a str {
445	        &self.s[self.pos..]
446	    }
447	
448	    fn ws(&mut self) {
449	        while let Some(c) = self.rest().chars().next() {
450	            if c.is_whitespace() {
451	                self.pos += c.len_utf8();
452	            } else {
453	                break;
454	            }
455	        }
456	    }
457	
458	    fn starts(&mut self, tok: &str) -> bool {
459	        self.ws();
460	        self.rest().starts_with(tok)
461	    }
462	
463	    fn eat(&mut self, tok: &str) -> bool {
464	        if self.starts(tok) {
465	            self.pos += tok.len();
466	            true
467	        } else {
468	            false
469	        }
470	    }
471	
472	    fn expect(&mut self, tok: &str) {
473	        assert!(
474	            self.eat(tok),
475	            "expected {tok:?} at …{:?}",
476	            &self.rest()[..self.rest().len().min(80)]
477	        );
478	    }
479	
480	    fn ident(&mut self) -> String {
481	        self.ws();
482	        let s: String = self
483	            .rest()
484	            .chars()
485	            .take_while(|c| c.is_ascii_alphanumeric() || *c == '_')
486	            .collect();
487	        assert!(
488	            !s.is_empty(),
489	            "expected ident at …{:?}",
490	            &self.rest()[..self.rest().len().min(60)]
491	        );
492	        self.pos += s.len();
493	        s
494	    }
495	
496	    fn digits(&mut self) -> String {
497	        let s: String = self
498	            .rest()
499	            .chars()
500	            .take_while(|c| c.is_ascii_digit())
501	            .collect();
502	        self.pos += s.len();
503	        s
504	    }
505	
506	    /// `name` or `name.idx` as a (name, idx) pair.
507	    fn name_idx(&mut self) -> (String, u64) {
508	        let name = self.ident();
509	        if self.rest().starts_with('.')
510	            && self.s[self.pos + 1..]
511	                .chars()
512	                .next()
513	                .is_some_and(|c| c.is_ascii_digit())
514	        {
515	            self.pos += 1;
516	            let idx = self.digits().parse().unwrap();
517	            (name, idx)
518	        } else {
519	            (name, 0)
520	        }
521	    }
522	
523	    fn quoted(&mut self) -> String {
524	        self.expect("'");
525	        let end = self.rest().find('\'').expect("unterminated quote");
526	        let s = self.rest()[..end].to_string();
527	        self.pos += end + 1;
528	        s
529	    }
530	
531	    // ── terms (as in round-2, plus nullary-application awareness) ──
532	
533	    fn term(&mut self) -> Term {
534	        let mut t = self.term_atom();
535	        while self.starts("^") {
536	            self.pos += 1;
537	            let rhs = self.term_atom();
538	            t = Term::BinOp(BinOp::Exp, Box::new(t), Box::new(rhs));
539	        }
540	        t
541	    }
542	
543	    fn sorted_var(&mut self, sort: SortHint) -> Term {
544	        let (name, idx) = self.name_idx();
545	        Term::Var(VarSpec {
546	            name,
547	            idx,
548	            sort,
549	            typ: None,
550	        })
551	    }
552	
553	    fn term_atom(&mut self) -> Term {
554	        self.ws();
555	        let c = self.rest().chars().next().expect("term expected");
556	        match c {
557	            '\'' => Term::PubLit(self.quoted()),
558	            '~' => {
559	                self.pos += 1;
560	                if self.rest().starts_with('\'') {
561	                    Term::FreshLit(self.quoted())
562	                } else {
563	                    self.sorted_var(SortHint::Fresh)
564	                }
565	            }
566	            '$' => {
567	                self.pos += 1;
568	                self.sorted_var(SortHint::Pub)
569	            }
570	            '#' => {
571	                self.pos += 1;
572	                self.sorted_var(SortHint::Node)
573	            }
574	            '%' => {
575	                self.pos += 1;
576	                if self
577	                    .rest()
578	                    .chars()
579	                    .next()
580	                    .is_some_and(|c| c.is_ascii_digit())
581	                {
582	                    Term::NatLit(self.digits())
583	                } else {
584	                    self.sorted_var(SortHint::Nat)
585	                }
586	            }
587	            '<' => {
588	                self.pos += 1;
589	                let mut elems = vec![self.term()];
590	                while self.eat(",") {
591	                    elems.push(self.term());
592	                }
593	                self.expect(">");
594	                Term::Pair(elems)
595	            }
596	            '(' => {
597	                self.pos += 1;
598	                let first = self.term();
599	                let op = if self.starts("++") {
600	                    BinOp::Union
601	                } else if self.starts("%+") {
602	                    BinOp::NatPlus
603	                } else if self.starts("\u{2295}") {
604	                    BinOp::Xor
605	                } else if self.starts("*") {
606	                    BinOp::Mult
607	                } else {
608	                    panic!(
609	                        "AC operator expected at …{:?}",
610	                        &self.rest()[..self.rest().len().min(60)]
611	                    );
612	                };
613	                let glyph = match op {
614	                    BinOp::Union => "++",
615	                    BinOp::NatPlus => "%+",
616	                    BinOp::Xor => "\u{2295}",
617	                    BinOp::Mult => "*",
618	                    BinOp::Exp => unreachable!(),
619	                };
620	                let mut t = first;
621	                while self.eat(glyph) {
622	                    let rhs = self.term();
623	                    t = Term::BinOp(op, Box::new(t), Box::new(rhs));
624	                }
625	                self.expect(")");
626	                t
627	            }
628	            _ => {
629	                let (name, idx) = self.name_idx();
630	                if self.rest().starts_with('(') {
631	                    // Application: nullary symbols render bare, so an
632	                    // argument list is always non-empty here (a nullary
633	                    // `Name( )` at formula-atom position is a FACT and is
634	                    // handled by `formula_atom`).
635	                    self.pos += 1;
636	                    let mut args = vec![self.term()];
637	                    while self.eat(",") {
638	                        args.push(self.term());
639	                    }
640	                    self.expect(")");
641	                    Term::App(name, args)
642	                } else {
643	                    Term::Var(VarSpec {
644	                        name,
645	                        idx,
646	                        sort: SortHint::Untagged,
647	                        typ: None,
648	                    })
649	                }
650	            }
651	        }
652	    }
653	
654	    // ── formulas ──
655	
656	    fn binder(&mut self) -> VarSpec {
657	        self.ws();
658	        let sort = if self.eat("~") {
659	            SortHint::Fresh
660	        } else if self.eat("$") {
661	            SortHint::Pub
662	        } else if self.eat("#") {
663	            SortHint::Node
664	        } else if self.eat("%") {
665	            SortHint::Nat
666	        } else {
667	            SortHint::Untagged
668	        };
669	        let (name, idx) = self.name_idx();
670	        VarSpec {
671	            name,
672	            idx,
673	            sort,
674	            typ: None,
675	        }
676	    }
677	
678	    fn quantifier(&mut self, glyph: &str) -> Formula {
679	        // Called with the glyph already known to be next.
680	        self.expect(glyph);
681	        let mut vs = Vec::new();
682	        loop {
683	            self.ws();
684	            if self.rest().starts_with('.') {
685	                self.pos += 1;
686	                break;
687	            }
688	            vs.push(self.binder());
689	        }
690	        let body = self.formula();
691	        if glyph == "\u{2200}" {
692	            Formula::Forall(vs, Box::new(body))
693	        } else {
694	            Formula::Exists(vs, Box::new(body))
695	        }
696	    }
697	
698	    fn formula(&mut self) -> Formula {
699	        self.ws();

698	    fn formula(&mut self) -> Formula {
699	        self.ws();
700	        if self.rest().starts_with('\u{2200}') {
701	            return self.quantifier("\u{2200}");
702	        }
703	        if self.rest().starts_with('\u{2203}') {
704	            return self.quantifier("\u{2203}");
705	        }
706	        let l = self.funit();
707	        self.ws();
708	        for (glyph, ctor) in [
709	            ("\u{2227}", Formula::And as fn(_, _) -> _),
710	            ("\u{2228}", Formula::Or as fn(_, _) -> _),
711	            ("\u{21d2}", Formula::Implies as fn(_, _) -> _),
712	            ("\u{21d4}", Formula::Iff as fn(_, _) -> _),
713	        ] {
714	            if self.eat(glyph) {
715	                let r = self.funit();
716	                // The statement printer parenthesizes every operand, so a
717	                // second connective at the same level cannot occur.
718	                self.ws();
719	                for g in ["\u{2227}", "\u{2228}", "\u{21d2}", "\u{21d4}"] {
720	                    assert!(
721	                        !self.rest().starts_with(g),
722	                        "unparenthesized connective chain at …{:?}",
723	                        &self.rest()[..self.rest().len().min(60)]
724	                    );
725	                }
726	                return ctor(Box::new(l), Box::new(r));
727	            }
728	        }
729	        l
730	    }
731	
732	    /// One operand-position formula unit.
733	    fn funit(&mut self) -> Formula {
734	        self.ws();
735	        if self.eat("\u{22a4}") {
736	            return Formula::True;
737	        }
738	        if self.eat("\u{22a5}") {
739	            return Formula::False;
740	        }
741	        if self.eat("\u{ac}") {
742	            self.expect("(");
743	            let f = self.formula();
744	            self.expect(")");
745	            return Formula::Not(Box::new(f));
746	        }
747	        if self.rest().starts_with('\u{2200}') {
748	            return self.quantifier("\u{2200}");
749	        }
750	        if self.rest().starts_with('\u{2203}') {
751	            return self.quantifier("\u{2203}");
752	        }
753	        if self.rest().starts_with('(') {
754	            // Ambiguity: `(` opens either a formula group or a
755	            // self-parenthesized AC term (`(x++z) = y`). A formula group is
756	            // followed by a connective or a closer; a term paren is followed
757	            // by a relation glyph. Decide by matching the paren.
758	            if !self.paren_is_term() {
759	                self.pos += 1;
760	                let f = self.formula();
761	                self.expect(")");
762	                return f;
763	            }
764	        }
765	        self.formula_atom()
766	    }
767	
768	    /// At a `(`: does this parenthesized span read as a TERM (its matching
769	    /// `)` is followed by a relation glyph) rather than a formula group?
770	    fn paren_is_term(&self) -> bool {
771	        let bytes = self.rest();
772	        let mut depth = 0usize;
773	        let mut it = bytes.char_indices();
774	        let close_end = loop {
775	            let Some((i, c)) = it.next() else { return false };
776	            match c {
777	                '(' => depth += 1,
778	                ')' => {
779	                    depth -= 1;
780	                    if depth == 0 {
781	                        break i + 1;
782	                    }
783	                }
784	                _ => {}
785	            }
786	        };
787	        let after = bytes[close_end..].trim_start();
788	        after.starts_with('=')
789	            || after.starts_with('<')
790	            || after.starts_with('\u{228f}')
791	            || after.starts_with('@')
792	    }
793	
794	    fn fact(&mut self) -> Fact {
795	        self.ws();
796	        let persistent = self.eat("!");
797	        let name = self.ident();
798	        self.expect("(");
799	        self.ws();
800	        let mut args = Vec::new();
801	        if !self.rest().starts_with(')') {
802	            args.push(self.term());
803	            while self.eat(",") {
804	                args.push(self.term());
805	            }
806	        }
807	        self.expect(")");
808	        Fact {
809	            persistent,
810	            name,
811	            args,
812	            annotations: vec![],
813	        }
814	    }
815	
816	    fn formula_atom(&mut self) -> Formula {
817	        self.ws();
818	        if self.rest().starts_with("last(") {
819	            self.pos += "last(".len();
820	            let t = self.term();
821	            self.expect(")");
822	            return Formula::Atom(Atom::Last(t));
823	        }
824	        if self.rest().starts_with('!') {
825	            let f = self.fact();
826	            self.expect("@");
827	            let tp = self.term();
828	            return Formula::Atom(Atom::Action(f, tp));
829	        }
830	        // Nullary fact `Name( )` cannot be parsed as a term; detect the
831	        // `ident( )` shape up front.
832	        let save = self.pos;
833	        let mut is_nullary_fact = false;
834	        if self.rest().chars().next().is_some_and(|c| c.is_ascii_alphanumeric() || c == '_') {
835	            let _ = self.ident();
836	            if self.starts("(") {
837	                self.pos += 1;
838	                if self.starts(")") {
839	                    is_nullary_fact = true;
840	                }
841	            }
842	        }
843	        self.pos = save;
844	        if is_nullary_fact {
845	            let f = self.fact();
846	            self.expect("@");
847	            let tp = self.term();
848	            return Formula::Atom(Atom::Action(f, tp));
849	        }
850	        let t = self.term();
851	        self.ws();
852	        if self.eat("@") {
853	            let (name, args) = match t {
854	                Term::App(name, args) => (name, args),
855	                Term::Var(v) => {
856	                    assert_eq!(v.idx, 0, "action fact head with index");
857	                    (v.name, vec![])
858	                }
859	                other => panic!("action atom on non-fact term {other:?}"),
860	            };
861	            let tp = self.term();
862	            return Formula::Atom(Atom::Action(
863	                Fact {
864	                    persistent: false,
865	                    name,
866	                    args,
867	                    annotations: vec![],
868	                },
869	                tp,
870	            ));
871	        }
872	        if self.eat("=") {
873	            let r = self.term();
874	            return Formula::Atom(Atom::Eq(t, r));
875	        }
876	        if self.eat("\u{228f}") {
877	            let r = self.term();
878	            return Formula::Atom(Atom::Subterm(t, r));
879	        }
880	        if self.eat("<") {
881	            let r = self.term();
882	            return Formula::Atom(Atom::Less(t, r));
883	        }
884	        panic!(
885	            "relation glyph expected at …{:?}",
886	            &self.rest()[..self.rest().len().min(60)]
887	        );
888	    }
889	
890	    // ── wrappers ──
891	
