//! TEMPORARY reproduction harness for blocker 3 (stack overflow on huge
//! variants blocks). Not part of the acceptance suite.

use pretty_clean::ast::*;
use pretty_clean::render_rule;

fn var(name: &str, idx: u64, sort: SortHint) -> Term {
    Term::Var(VarSpec { name: name.into(), idx, sort, typ: None })
}
fn fresh(name: &str) -> Term { var(name, 0, SortHint::Fresh) }
fn fact(name: &str, args: Vec<Term>) -> Fact {
    Fact { persistent: false, name: name.into(), args, annotations: vec![] }
}

fn big_variants(n_groups: usize) -> (Rule, AcVariants) {
    let r = Rule {
        name: "Big".into(),
        modulo: Some("E".into()),
        attributes: vec![],
        premises: vec![fact("Fr", vec![fresh("a")])],
        actions: vec![],
        conclusions: vec![fact("Out", vec![fresh("a")])],
        loop_breakers: vec![],
    };
    let ac = Rule { modulo: Some("AC".into()), ..r.clone() };
    let mut groups = Vec::new();
    for _ in 0..n_groups {
        groups.push(vec![
            (fresh("a"), var("a", 4, SortHint::Fresh)),
            (fresh("b"), var("b", 4, SortHint::Fresh)),
        ]);
    }
    (r, AcVariants { ac_rule: ac, substitutions: groups })
}

#[test]
fn repro_default_stack() {
    // Runs on the test's main thread (default process stack, ~8MB) to mimic
    // production. Increase N to find the overflow threshold.
    for n in [100usize, 500, 1000, 2000, 4000, 8000] {
        let (r, v) = big_variants(n);
        let out = render_rule(&r, Some(&v));
        eprintln!("N={n} ok, {} bytes", out.len());
    }
}

