/// `reduceDoc`: push `Beside`/`Above` down into reduced form (RDoc).
pub fn reduce_doc(d: &Doc) -> Doc {
    match d {
        Beside(p, g, q) => beside(p, *g, &reduce_doc(q)),
        Above(p, g, q) => above(p, *g, &reduce_doc(q)),
